+    for (const [keyId, score] of scores) {
+      const expScore = Math.exp(score - maxScore);
+      attentionWeights.set(keyId, expScore);
+      sumExp += expScore;
+    }
+
+    // Normalize
+    for (const [keyId, weight] of attentionWeights) {
+      attentionWeights.set(keyId, weight / sumExp);
